252	impl LocatorInspector {
253	    pub fn is_reliable(&self, locator: &Locator) -> ZResult<bool> {
254	        #[allow(unused_imports)]
255	        use zenoh_link_commons::LocatorInspector;
256	        match LinkKind::try_from(locator)? {
257	            #[cfg(feature = "transport_tcp")]
258	            LinkKind::Tcp => self.tcp_inspector.is_reliable(locator),
259	            #[cfg(feature = "transport_udp")]
260	            LinkKind::Udp => self.udp_inspector.is_reliable(locator),
261	            #[cfg(feature = "transport_tls")]
262	            LinkKind::Tls => self.tls_inspector.is_reliable(locator),
263	            #[cfg(feature = "transport_quic")]
264	            LinkKind::Quic => self.quic_inspector.is_reliable(locator),
265	            #[cfg(feature = "transport_quic_datagram")]
266	            LinkKind::QuicDatagram => self.quic_datagram_inspector.is_reliable(locator),
267	            #[cfg(all(feature = "transport_unixsock-stream", target_family = "unix"))]
268	            LinkKind::UnixsockStream => self.unixsock_stream_inspector.is_reliable(locator),
269	            #[cfg(feature = "transport_ws")]
270	            LinkKind::Ws => self.ws_inspector.is_reliable(locator),
271	            #[cfg(feature = "transport_serial")]
272	            LinkKind::Serial => self.serial_inspector.is_reliable(locator),
273	            #[cfg(feature = "transport_unixpipe")]
274	            LinkKind::Unixpipe => self.unixpipe_inspector.is_reliable(locator),
275	            #[cfg(all(feature = "transport_vsock", target_os = "linux"))]
276	            LinkKind::Vscock => self.vsock_inspector.is_reliable(locator),
