331	impl LinkConfigurator {
332	    #[allow(unused_variables, unused_mut)]
333	    pub fn configurations(
334	        &self,
335	        config: &Config,
336	    ) -> (
337	        HashMap<LinkKind, String>,
338	        HashMap<LinkKind, zenoh_result::Error>,
339	    ) {
340	        let mut configs = HashMap::<LinkKind, String>::new();
341	        let mut errors = HashMap::<LinkKind, zenoh_result::Error>::new();
342	        let mut insert_config = |kind: LinkKind, cfg: ZResult<String>| match cfg {
343	            Ok(v) => {
344	                configs.insert(kind, v);
345	            }
346	            Err(e) => {
347	                errors.insert(kind, e);
348	            }
349	        };
350	        #[cfg(feature = "transport_tcp")]
351	        {
352	            insert_config(LinkKind::Tcp, self.tcp_inspector.inspect_config(config));
353	        }
354	        #[cfg(feature = "transport_quic_datagram")]
355	        {
356	            insert_config(
357	                LinkKind::QuicDatagram,
358	                self.quic_datagram_inspector.inspect_config(config),
359	            );
360	        }
361	        #[cfg(feature = "transport_quic")]
362	        {
363	            insert_config(LinkKind::Quic, self.quic_inspector.inspect_config(config));
364	        }
365	        #[cfg(feature = "transport_tls")]
366	        {
367	            insert_config(LinkKind::Tls, self.tls_inspector.inspect_config(config));
368	        }
369	        #[cfg(feature = "transport_unixpipe")]
370	        {
371	            insert_config(
372	                LinkKind::Unixpipe,
373	                self.unixpipe_inspector.inspect_config(config),
374	            );
375	        }
376	        (configs, errors)
377	    }
378	}
