37	const L_LEN: usize = (BatchSize::BITS / 8) as usize;
38	const H_LEN: usize = BatchHeader::SIZE;
39	
40	// Split the inner buffer into (length, header, payload) immutable slices
41	macro_rules! zsplit {
42	    ($slice:expr, $config:expr) => {{
43	        match ($config.is_streamed, $config.has_header()) {
44	            (true, true) => {
45	                let (l, s) = $slice.split_at(L_LEN);
46	                let (h, p) = s.split_at(H_LEN);
47	                (l, h, p)
48	            }
49	            (true, false) => {
50	                let (l, p) = $slice.split_at(L_LEN);
51	                (l, &[], p)
52	            }
53	            (false, true) => {
54	                let (h, p) = $slice.split_at(H_LEN);
55	                (&[], h, p)
56	            }
57	            (false, false) => (&[], &[], $slice),
58	        }
59	    }};
60	}
61	
62	macro_rules! zsplit_mut {
63	    ($slice:expr, $config:expr) => {{
64	        match ($config.is_streamed, $config.has_header()) {
65	            (true, true) => {
66	                let (l, s) = $slice.split_at_mut(L_LEN);
67	                let (h, p) = s.split_at_mut(H_LEN);
68	                (l, h, p)
69	            }
70	            (true, false) => {
71	                let (l, p) = $slice.split_at_mut(L_LEN);
72	                (l, &mut [], p)
73	            }
74	            (false, true) => {
75	                let (h, p) = $slice.split_at_mut(H_LEN);
76	                (&mut [], h, p)
77	            }
78	            (false, false) => (&mut [], &mut [], $slice),
79	        }
80	    }};
81	}
